import{_ as a,o as i,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"32B. Sole Midwife Allowance","description":"","frontmatter":{"title":"32B. Sole Midwife Allowance","eba":"Nurses and Midwives 2024-2028","topics":["hours","shift-work","allowances","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/32B-sole-midwife-allowance.md","filePath":"ebas/nurses-midwives/allowances/32B-sole-midwife-allowance.md"}'),t={name:"ebas/nurses-midwives/allowances/32B-sole-midwife-allowance.md"};function n(r,e,l,d,w,c){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_32b-sole-midwife-allowance" tabindex="-1">32B. Sole Midwife Allowance <a class="header-anchor" href="#_32b-sole-midwife-allowance" aria-label="Permalink to &quot;32B. Sole Midwife Allowance&quot;">​</a></h1><p><strong>(a)</strong> FFPPOOA 1 May 2024, a Midwife is entitled to be paid a Sole Midwife Allowance in accordance with <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2, for each shift worked where:</p><p><strong>(i)</strong> The ward provides maternity service care inclusive of one or more of the following: antenatal, post-natal, birthing suites or maternity assessment services and non-maternity service care;</p><p><strong>(ii)</strong> the Registered Nurse in charge of the ward on a shift is not also a Midwife; and</p><p><strong>(iii)</strong> the Midwife is the sole Midwife on duty within that ward (regardless of any on-call midwife or caseload model midwife).</p><p><strong>(b)</strong> In the circumstances of (a), a Midwife working on that ward, on that shift, will be recorded in writing (which could include a notation on the roster) as the Sole Midwife for that shift.</p>',6)])])}const m=a(t,[["render",n]]);export{h as __pageData,m as default};
